var SeatManager = function(n) {
    this.heap = [];
    this.next = 1;
};
SeatManager.prototype._up = function(i) {
    const h = this.heap;
    while (i > 0) {
        const p = (i - 1) >> 1;
        if (h[p] <= h[i]) break;
        [h[p], h[i]] = [h[i], h[p]];
        i = p;
    }
};
SeatManager.prototype._down = function(i) {
    const h = this.heap, n = h.length;
    while (true) {
        let s = i, l = 2 * i + 1, r = 2 * i + 2;
        if (l < n && h[l] < h[s]) s = l;
        if (r < n && h[r] < h[s]) s = r;
        if (s === i) break;
        [h[s], h[i]] = [h[i], h[s]];
        i = s;
    }
};
SeatManager.prototype.reserve = function() {
    if (this.heap.length && this.heap[0] < this.next) {
        const top = this.heap[0];
        const last = this.heap.pop();
        if (this.heap.length) { this.heap[0] = last; this._down(0); }
        return top;
    }
    return this.next++;
};
SeatManager.prototype.unreserve = function(seatNumber) {
    if (seatNumber < this.next) {
        this.heap.push(seatNumber);
        this._up(this.heap.length - 1);
    }
};
